import org.jsoup.helper.DataUtil;
import org.jsoup.helper.HttpConnection;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.jsoup.safety.Safelist;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.nio.file.Files;
import java.nio.file.Path;

import static org.junit.jupiter.api.Assertions.*;
public class Jsoup_parse_1_Test {

    @Test
    @DisplayName("parse(File, charsetName) uses file path as baseUri when charsetName non-null")
    public void test_TC11() throws Exception {
        Path temp = Files.createTempFile("test11", ".html");
        Files.write(temp, "<p>foo</p>".getBytes("UTF-8"));
        File f = temp.toFile();
        String charset = "UTF-8";
        Document doc = Jsoup.parse(f, charset);
        assertEquals("<p>foo</p>", doc.body().html(), "Should parse body HTML correctly");
        assertEquals(f.getAbsolutePath(), doc.baseUri(), "Base URI must be the file absolute path");
    }

    @Test
    @DisplayName("parse(File) determines charsetName=null, baseUri=file path, returns parsed document")
    public void test_TC12() throws Exception {
        Path temp = Files.createTempFile("test12", ".html");
        Files.write(temp, "<div>bar</div>".getBytes("UTF-8"));
        File f = temp.toFile();
        Document doc = Jsoup.parse(f);
        assertEquals("<div>bar</div>", doc.body().html(), "Should parse body HTML correctly");
        assertEquals(f.getAbsolutePath(), doc.baseUri(), "Base URI must be the file absolute path");
    }

    @Test
    @DisplayName("parse(File, charsetName, baseUri, parser) throws IOException on invalid charsetName")
    public void test_TC13() throws Exception {
        Path temp = Files.createTempFile("test13", ".html");
        Files.write(temp, "<p>x</p>".getBytes("UTF-8"));
        File f = temp.toFile();
        String badCharset = "INVALID-CHARSET";
        Parser parser = Parser.htmlParser();
        assertThrows(IOException.class,
            () -> Jsoup.parse(f, badCharset, "http://base/", parser),
            "Invalid charset should cause IOException");
    }

    @Test
    @DisplayName("parse(Path, charsetName, baseUri) succeeds reading from Path")
    public void test_TC14() throws Exception {
        Path p = Files.createTempFile("test14", ".html");
        Files.write(p, "<span>z</span>".getBytes("UTF-8"));
        String charset = "UTF-8";
        String baseUri = "http://x/";
        Document doc = Jsoup.parse(p, charset, baseUri);
        assertEquals("<span>z</span>", doc.body().html(), "Should parse body HTML correctly");
        assertEquals(baseUri, doc.baseUri(), "Base URI must match provided baseUri");
    }

    @Test
    @DisplayName("parse(Path, charsetName) uses path.toAbsolutePath() as baseUri with charsetName non-null")
    public void test_TC15() throws Exception {
        Path p = Files.createTempFile("test15", ".html");
        Files.write(p, "<em>e</em>".getBytes("UTF-8"));
        String charset = "UTF-8";
        Document doc = Jsoup.parse(p, charset);
        assertEquals("<em>e</em>", doc.body().html(), "Should parse body HTML correctly");
        assertEquals(p.toAbsolutePath().toString(), doc.baseUri(), "Base URI must be the path's absolute path");
    }

    @Test
    @DisplayName("parse(Path) determines charsetName=null and baseUri as absolute path")
    public void test_TC16() throws Exception {
        Path p = Files.createTempFile("test16", ".html");
        Files.write(p, "<i>i</i>".getBytes("UTF-8"));
        Document doc = Jsoup.parse(p);
        assertEquals("<i>i</i>", doc.body().html(), "Should parse body HTML correctly");
        assertEquals(p.toAbsolutePath().toString(), doc.baseUri(), "Base URI must be the path's absolute path");
    }

    @Test
    @DisplayName("parse(Path, charsetName, baseUri, parser) succeeds with XML parser")
    public void test_TC17() throws Exception {
        Path p = Files.createTempFile("test17", ".xml");
        Files.write(p, "<root/>".getBytes("UTF-8"));
        Parser parser = Parser.xmlParser();
        String baseUri = "http://b/";
        Document doc = Jsoup.parse(p, null, baseUri, parser);
        assertNotNull(doc.selectFirst("root"), "XML parser should produce <root> element");
        assertEquals(baseUri, doc.baseUri(), "Base URI must match provided baseUri");
    }

    @Test
    @DisplayName("parse(InputStream, charsetName, baseUri, parser) closes stream after parse")
    public void test_TC18() throws Exception {
        byte[] data = "<a/>".getBytes("UTF-8");
        ByteArrayInputStream in = new ByteArrayInputStream(data);
        Parser parser = Parser.xmlParser();
        Document doc = Jsoup.parse(in, "UTF-8", "http://b/", parser);
        assertNotNull(doc.selectFirst("a"), "XML parser should produce <a> element");
        assertEquals(-1, in.read(), "InputStream should be closed after parse");
    }

    @Test
    @DisplayName("parseBodyFragment(String, String) resolves relative links when baseUri non-empty")
    public void test_TC19() {
        String html = "<a href=\"r.html\">x</a>";
        String base = "http://u/";
        Document doc = Jsoup.parseBodyFragment(html, base);
        String abs = doc.body().selectFirst("a").attr("abs:href");
        assertEquals("http://u/r.html", abs, "Relative link should be resolved to absolute URL");
    }

    @Test
    @DisplayName("parseBodyFragment(String) uses empty baseUri and returns fragment")
    public void test_TC20() {
        String html = "<p>z</p>";
        Document doc = Jsoup.parseBodyFragment(html);
        assertEquals("<p>z</p>", doc.body().html(), "Should parse fragment correctly");
        assertEquals("", doc.baseUri(), "Base URI should be empty string");
    }
}
